function scoreFromComposite(judgment) {
  return typeof judgment.composite === 'number' ? Math.round(judgment.composite * 100) : null;
}

function buildVariantRecord(msg, judgment, judgeScore0to100) {
  return {
    correlationId: msg.correlationId || msg.evalGroupCorrelationId || null,
    scenarioId: msg.evalScenario?.id || 'unknown',
    variantLabel: msg.evalVariantLabel || judgment.variantLabel || 'unknown',
    isBaseline: msg.evalVariant?.baseline === true,
    runEvalTaskId: msg.evalJudgeTargetTaskId || msg.evalTaskId || null,
