}

function upsertScenarioResult(record) {
  const groups = flow.get('abEvalResults') || {};
  const group = groups[record.correlationId] || {
    correlationId: record.correlationId,
    expectedVariants: {},
    scenarios: {},
    createdAt: new Date().toISOString()
  };
