  scenario[record.variantLabel] = record;
  group.scenarios[record.scenarioId] = scenario;
  group.updatedAt = new Date().toISOString();
  groups[record.correlationId] = group;
  flow.set('abEvalResults', groups);
  return { group, scenario };
}

function rankedVariants(scenario) {
  return Object.values(scenario)
    .filter((item) => typeof item.judgeScore0to100 === 'number')
    .sort((a, b) => b.judgeScore0to100 - a.judgeScore0to100);
}

function buildDelta(scenario) {
  const records = Object.values(scenario);
  const baseline = records.find((item) => item.isBaseline || item.variantLabel === 'baseline-no-skill' || item.variantLabel === 'baseline');
  const candidate = records
    .filter((item) => item !== baseline && typeof item.judgeScore0to100 === 'number')
    .sort((a, b) => b.judgeScore0to100 - a.judgeScore0to100)[0] || null;
  if (!baseline || !candidate) return null;
  return {
    baselineVariant: baseline.variantLabel,
    candidateVariant: candidate.variantLabel,
    baselineScore0to100: baseline.judgeScore0to100,
    candidateScore0to100: candidate.judgeScore0to100,
    judgeDelta0to100: baseline.judgeScore0to100 === null || candidate.judgeScore0to100 === null ? null : candidate.judgeScore0to100 - baseline.judgeScore0to100,
    baselineProducerScore0to100: baseline.producerScore0to100,
    candidateProducerScore0to100: candidate.producerScore0to100,
    producerDelta0to100: baseline.producerScore0to100 === null || candidate.producerScore0to100 === null ? null : candidate.producerScore0to100 - baseline.producerScore0to100
  };
}

